   108→      const localBackendCallback = config.onStateUpdate || backendUpdateCallback;
   109→      const localIsEnabled = config.enabled !== false;
   110→      
   111→      // Create a coalesced set function
   112→      const coalescedSet = (updater: any) => {
   113→        // Apply the state change immediately for UI responsiveness
   114→        const result = set(updater);
   115→        
   116→        // If we have a viewState in the new state, coalesce the backend update
   117→        const newState = get();
   118→        if (newState && newState.viewState && localIsEnabled) {
   119→          const queueTime = performance.now();
   120→          console.log(`[coalesceMiddleware ${queueTime.toFixed(0)}ms] 📥 QUEUING state update:`);
