   122→          console.log(`  - layer ids:`, newState.viewState.layers.map(l => l.id));
   123→          console.log(`  - layer details:`, newState.viewState.layers.map(l => ({
   124→            id: l.id,
   125→            volumeId: l.volumeId,
   126→            visible: l.visible,
   127→            opacity: l.opacity,
   128→            intensity: l.intensity,
   129→            threshold: l.threshold,
   130→            colormap: l.colormap
   131→          })));
   132→          
   133→          // Check for problematic intensity values being queued
   134→          newState.viewState.layers.forEach(layer => {
   135→            if (layer.intensity && 
   136→                layer.intensity[0] > 1969 && layer.intensity[0] < 1970 &&
   137→                layer.intensity[1] > 7878 && layer.intensity[1] < 7879) {
   138→              console.error(`[coalesceMiddleware] 📥 QUEUING PROBLEMATIC INTENSITY VALUES for layer ${layer.id}:`, layer.intensity);
   139→              console.trace('Stack trace for problematic queue:');
   140→            }
   141→          });
   142→          
   143→          // Store the latest state for batching
   144→          pendingState = newState.viewState;
   145→          
   146→          // Update global callback if provided locally
   147→          if (localBackendCallback) {
   148→            backendUpdateCallback = localBackendCallback;
   149→          }
   150→          
