import React, { useState, useRef, useCallback, useEffect } from 'react';

interface ProSliderProps {
  min: number;
  max: number;
  value: [number, number];
  label: string;
  onChange: (value: [number, number]) => void;
  precision?: number;
  showTooltip?: boolean;
  className?: string;
}

export const ProSlider: React.FC<ProSliderProps> = ({
  min,
  max,
  value,
  label,
  onChange,
  precision = 0,
  showTooltip = true,
  className = ''
}) => {
  const [localValue, setLocalValue] = useState(value);
  const [isDragging, setIsDragging] = useState(false);
  const [activeThumb, setActiveThumb] = useState<'left' | 'right' | null>(null);
  const [tooltipPosition, setTooltipPosition] = useState({ left: 0, right: 0 });
  const trackRef = useRef<HTMLDivElement>(null);
  const leftThumbRef = useRef<HTMLDivElement>(null);
  const rightThumbRef = useRef<HTMLDivElement>(null);

  // Track last update time for throttling
  const lastUpdateRef = useRef(0);
  const THROTTLE_MS = 50; // Update at most every 50ms

  // Call onChange with throttling
  const handleValueChange = useCallback((newValue: [number, number]) => {
    setLocalValue(newValue);

    const now = Date.now();
    if (now - lastUpdateRef.current >= THROTTLE_MS) {
      // Track the exact value we're sending
      lastSentValueRef.current = newValue;
      onChange(newValue);
      lastUpdateRef.current = now;
    }
  }, [onChange]);

  // Format value for display
  const formatValue = (val: number): string => {
    // Use consistent formatting
    if (val >= 1e4) return `${(val / 1000).toFixed(1)}K`;
    if (val <= -1e4) return `${(val / 1000).toFixed(1)}K`;
    return val.toFixed(0);
  };

  // Convert value to position percentage
  const valueToPercent = (val: number): number => {
    return ((val - min) / (max - min)) * 100;
  };

  // Convert position to value
  const percentToValue = (percent: number): number => {
    return min + (percent / 100) * (max - min);
  };

  // Handle thumb drag
  const handleThumbDrag = useCallback((e: MouseEvent, thumb: 'left' | 'right') => {
    if (!trackRef.current) return;

    const rect = trackRef.current.getBoundingClientRect();
    const percent = Math.max(0, Math.min(100, ((e.clientX - rect.left) / rect.width) * 100));
    const newValue = percentToValue(percent);

    const [currentLeft, currentRight] = localValue;
    let updatedValue: [number, number];

    if (thumb === 'left') {
      // Ensure left thumb doesn't go past right thumb
      updatedValue = [Math.min(newValue, currentRight), currentRight];
    } else {
      // Ensure right thumb doesn't go past left thumb
      updatedValue = [currentLeft, Math.max(newValue, currentLeft)];
    }

    handleValueChange(updatedValue);
  }, [min, max, localValue, handleValueChange]);

  // Mouse event handlers
  const handleMouseDown = (thumb: 'left' | 'right') => (e: React.MouseEvent) => {
    e.preventDefault();
    setIsDragging(true);
    setActiveThumb(thumb);

    const handleMouseMove = (e: MouseEvent) => {
      handleThumbDrag(e, thumb);
    };

    const handleMouseUp = () => {
      setIsDragging(false);
      setActiveThumb(null);

      // Always send final value on drag end (bypass throttling)
      lastSentValueRef.current = localValue;
      onChange(localValue);
      lastUpdateRef.current = 0; // Reset throttle for next drag

      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  // Update tooltip positions
  useEffect(() => {
    const leftPercent = valueToPercent(localValue[0]);
    const rightPercent = valueToPercent(localValue[1]);
    setTooltipPosition({ left: leftPercent, right: rightPercent });
  }, [localValue, min, max]);

  // Track the last value we sent to prevent immediate echo
  const lastSentValueRef = useRef<[number, number] | null>(null);

  // Update local value when prop changes (but not while dragging)
  useEffect(() => {
    if (!isDragging) {
      // Check if this is exactly the value we just sent
      const isEcho = lastSentValueRef.current && 
        Math.abs(lastSentValueRef.current[0] - value[0]) < 0.001 &&
        Math.abs(lastSentValueRef.current[1] - value[1]) < 0.001;

      if (isEcho) {
        // Clear the ref so we don't ignore future updates
        lastSentValueRef.current = null;
        return;
      }

      // Only update if values are different
      const [currentMin, currentMax] = localValue;
      const [newMin, newMax] = value;

      if (Math.abs(currentMin - newMin) > 0.001 || Math.abs(currentMax - newMax) > 0.001) {
        // console.log(`[ProSlider ${label}] Updating from external value change:`, 
        //   `[${currentMin.toFixed(1)}, ${currentMax.toFixed(1)}] -> [${newMin.toFixed(1)}, ${newMax.toFixed(1)}]`);
        setLocalValue(value);
      }
    }
  }, [value, isDragging, label]); // Removed localValue to prevent race condition

  const leftPercent = valueToPercent(localValue[0]);
  const rightPercent = valueToPercent(localValue[1]);

  return (
    <div className={`pro-slider ${className}`} style={{ marginBottom: '24px' }}>
      {/* Label */}
      <label className="block text-[13px] font-medium" style={{ color: 'var(--layer-text)', marginBottom: '8px' }}>
        {label}
      </label>

      {/* Value display */}
      <div className="flex justify-between text-[11px] font-mono tabular-nums text-neutral-400" style={{ marginBottom: '12px' }}>
        <span>{formatValue(localValue[0])}</span>
        <span>{formatValue(localValue[1])}</span>
      </div>

      {/* Slider track */}
      <div className="relative h-8 flex items-center">
        <div
          ref={trackRef}
          className="relative w-full h-[3px] rounded-full"
          style={{ backgroundColor: 'var(--layer-track-bg)' }}
        >
          {/* Selected range */}
          <div
            className="absolute h-full rounded-full"
            style={{
              backgroundColor: 'var(--layer-accent)',
              left: `${leftPercent}%`,
              width: `${rightPercent - leftPercent}%`
            }}
          />

          {/* Left thumb */}
          <div
            ref={leftThumbRef}
            className="absolute top-1/2 -translate-y-1/2 -translate-x-1/2 cursor-pointer"
            style={{ left: `${leftPercent}%` }}
            onMouseDown={handleMouseDown('left')}
          >
            <div
              className="w-[14px] h-[14px] rounded-full border border-white shadow-[0_0_2px_black] transition-transform absolute top-[-5px]"
              style={{
                backgroundColor: 'var(--layer-accent)',
                transform: isDragging && activeThumb === 'left' ? 'scale(1.1)' : 'scale(1)'
              }}
            />
            {/* Tooltip */}
            {showTooltip && isDragging && activeThumb === 'left' && (
              <div
                className="absolute -top-7 left-1/2 -translate-x-1/2 px-2 py-1 text-[11px] text-white rounded shadow-lg pointer-events-none whitespace-nowrap"
                style={{ backgroundColor: 'rgba(0, 0, 0, 0.8)' }}
              >
                {formatValue(localValue[0])}
              </div>
            )}
          </div>

          {/* Right thumb */}
          <div
            ref={rightThumbRef}
            className="absolute top-1/2 -translate-y-1/2 -translate-x-1/2 cursor-pointer"
            style={{ left: `${rightPercent}%` }}
            onMouseDown={handleMouseDown('right')}
          >
            <div
              className="w-[14px] h-[14px] rounded-full border border-white shadow-[0_0_2px_black] transition-transform absolute top-[-5px]"
              style={{
                backgroundColor: 'var(--layer-accent)',
                transform: isDragging && activeThumb === 'right' ? 'scale(1.1)' : 'scale(1)'
              }}
            />
            {/* Tooltip */}
            {showTooltip && isDragging && activeThumb === 'right' && (
              <div
                className="absolute -top-7 left-1/2 -translate-x-1/2 px-2 py-1 text-[11px] text-white rounded shadow-lg pointer-events-none whitespace-nowrap"
                style={{ backgroundColor: 'rgba(0, 0, 0, 0.8)' }}
              >
                {formatValue(localValue[1])}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

